import { describe, it, expect } from 'vitest';
import { priceOrder } from '../src/pricing.js';

describe('priceOrder — subtotal', () => {
  it('returns all zeros for an empty order', () => {
    expect(priceOrder([])).toEqual({
      subtotalCents: 0,
      discountCents: 0,
      totalCents: 0,
    });
  });

  it('sums unitCents * qty across a single line', () => {
    expect(priceOrder([{ unitCents: 2000, qty: 3 }])).toEqual({
      subtotalCents: 6000,
      discountCents: 0,
      totalCents: 6000,
    });
  });

  it('sums unitCents * qty across multiple lines', () => {
    // 3000*2 + 2000*3 = 6000 + 6000 = 12000
    const { subtotalCents } = priceOrder([
      { unitCents: 3000, qty: 2 },
      { unitCents: 2000, qty: 3 },
    ]);
    expect(subtotalCents).toBe(12000);
  });
});

describe('priceOrder — tier discount', () => {
  it('applies no tier discount below the 10000 threshold', () => {
    expect(priceOrder([{ unitCents: 5000, qty: 1 }])).toEqual({
      subtotalCents: 5000,
      discountCents: 0,
      totalCents: 5000,
    });
  });

  it('applies no tier discount just under the threshold (9999)', () => {
    const result = priceOrder([{ unitCents: 9999, qty: 1 }]);
    expect(result.discountCents).toBe(0);
    expect(result.totalCents).toBe(9999);
  });

  it('applies a 10% tier discount exactly at the threshold (10000)', () => {
    expect(priceOrder([{ unitCents: 10000, qty: 1 }])).toEqual({
      subtotalCents: 10000,
      discountCents: 1000,
      totalCents: 9000,
    });
  });

  it('applies 10% of the subtotal above the threshold', () => {
    // 20000 -> 2000
    expect(priceOrder([{ unitCents: 10000, qty: 2 }])).toEqual({
      subtotalCents: 20000,
      discountCents: 2000,
      totalCents: 18000,
    });
  });

  it('rounds the tier discount to the nearest cent (down)', () => {
    // 10004 * 0.1 = 1000.4 -> 1000
    expect(priceOrder([{ unitCents: 10004, qty: 1 }]).discountCents).toBe(1000);
  });

  it('rounds a .5 tier discount up', () => {
    // 10005 * 0.1 = 1000.5 -> 1001
    expect(priceOrder([{ unitCents: 10005, qty: 1 }])).toEqual({
      subtotalCents: 10005,
      discountCents: 1001,
      totalCents: 9004,
    });
  });

  it('rounds the tier discount up when just above .5', () => {
    // 10006 * 0.1 = 1000.6 -> 1001
    expect(priceOrder([{ unitCents: 10006, qty: 1 }]).discountCents).toBe(1001);
  });
});

describe('priceOrder — coupon discount', () => {
  it('ignores a missing coupon', () => {
    const result = priceOrder([{ unitCents: 5000, qty: 1 }]);
    expect(result.discountCents).toBe(0);
  });

  it('applies the coupon pct to the subtotal when there is no tier discount', () => {
    // 5000 * 10% = 500
    expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 10 })).toEqual({
      subtotalCents: 5000,
      discountCents: 500,
      totalCents: 4500,
    });
  });

  it('applies the coupon pct to the subtotal AFTER the tier discount', () => {
    // subtotal 10000, tier 1000, afterTier 9000, coupon 30% of 9000 = 2700
    // discount = 1000 + 2700 = 3700
    expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 30 })).toEqual({
      subtotalCents: 10000,
      discountCents: 3700,
      totalCents: 6300,
    });
  });

  it('combines tier and coupon discounts across multiple lines', () => {
    // subtotal 12000, tier 1200, afterTier 10800, coupon 20% of 10800 = 2160
    // discount = 1200 + 2160 = 3360
    expect(
      priceOrder(
        [
          { unitCents: 3000, qty: 2 },
          { unitCents: 2000, qty: 3 },
        ],
        { pct: 20 }
      )
    ).toEqual({
      subtotalCents: 12000,
      discountCents: 3360,
      totalCents: 8640,
    });
  });

  it('treats a 0% coupon as no coupon discount', () => {
    expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 0 })).toEqual({
      subtotalCents: 10000,
      discountCents: 1000,
      totalCents: 9000,
    });
  });

  it('rounds a .5 coupon discount up', () => {
    // no tier (subtotal 5 < 10000); 5 * 10% = 0.5 -> 1
    expect(priceOrder([{ unitCents: 5, qty: 1 }], { pct: 10 })).toEqual({
      subtotalCents: 5,
      discountCents: 1,
      totalCents: 4,
    });
  });

  it('rounds a coupon discount down when below .5', () => {
    // subtotal 4, 4 * 10% = 0.4 -> 0
    expect(priceOrder([{ unitCents: 4, qty: 1 }], { pct: 10 }).discountCents).toBe(0);
  });
});

describe('priceOrder — coupon cap at 30%', () => {
  it('does not cap a pct at exactly 30', () => {
    // subtotal 10000, tier 1000, afterTier 9000, 30% = 2700
    expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 30 }).discountCents).toBe(3700);
  });

  it('caps a pct above 30 at 30', () => {
    // pct 50 is treated as 30 -> same result as pct 30
    expect(priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 50 })).toEqual(
      priceOrder([{ unitCents: 10000, qty: 1 }], { pct: 30 })
    );
  });

  it('caps a pct of 100 at 30', () => {
    // subtotal 5000, no tier, 30% of 5000 = 1500
    expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 100 })).toEqual({
      subtotalCents: 5000,
      discountCents: 1500,
      totalCents: 3500,
    });
  });

  it('does not cap a pct just below 30', () => {
    // subtotal 5000, 29% = 1450
    expect(priceOrder([{ unitCents: 5000, qty: 1 }], { pct: 29 }).discountCents).toBe(1450);
  });
});

describe('priceOrder — qty validation', () => {
  it('throws RangeError for a qty of 0', () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 0 }])).toThrow(RangeError);
  });

  it('throws RangeError for a negative qty', () => {
    expect(() => priceOrder([{ unitCents: 100, qty: -1 }])).toThrow(RangeError);
  });

  it('throws RangeError for a non-integer qty', () => {
    expect(() => priceOrder([{ unitCents: 100, qty: 1.5 }])).toThrow(RangeError);
  });

  it('throws RangeError for a non-numeric qty', () => {
    expect(() => priceOrder([{ unitCents: 100, qty: NaN }])).toThrow(RangeError);
  });

  it('throws when any line has an invalid qty', () => {
    expect(() =>
      priceOrder([
        { unitCents: 100, qty: 2 },
        { unitCents: 200, qty: 0 },
      ])
    ).toThrow(RangeError);
  });

  it('accepts a qty of 1', () => {
    expect(priceOrder([{ unitCents: 100, qty: 1 }]).subtotalCents).toBe(100);
  });
});

